let items=$input.all(),r=[];
for(let it of items){
 let msg=it.json,from='',sub='',email='',name='';
 if(msg.from||msg.From)from=msg.from||msg.From||'';
 if(msg.subject||msg.Subject)sub=msg.subject||msg.Subject||'';
 if(!from&&msg.payload&&msg.payload.headers){
  let h=msg.payload.headers;
  if(Array.isArray(h)){
   let f=h.find(x=>x&&x.name==='From'),s=h.find(x=>x&&x.name==='Subject');
   from=f?f.value||'':'';sub=sub||(s?s.value||'':'');
  }else{from=h.from||h.From||'';sub=sub||h.subject||h.Subject||''}
 }
 if(!from){r.push({json:{_skip:true}});continue}
 let m=from.match(/<?([^>@]+@[^>]+)>?/);
 if(m)email=m[1].trim();else{let parts=from.split(' ');for(let p of parts){if(p.includes('@')){email=p.replace(/[<>]/g,'');break}}}
 if(!email)email=from;name=from.replace(/<.*>/,'').replace(/"/g,'').trim()||email;
 let body=msg.snippet||'';if(!sub)sub='(no subject)';
 let prompt='You are Digital Clone. Email: '+name+' Subject: '+sub+' Body: '+body.substring(0,800)+' If this needs a reply, write ONLY the reply text under 300 chars. If informational, write SKIP.';
 r.push({json:{_prompt:prompt,_name:name,_email:email,_sub:sub,_snippet:body.substring(0,100),_mid:msg.id||'',_tid:msg.threadId||''}})
}
return r

let items=$input.all(),r=[];
let sd=$getWorkflowStaticData('global');
if(!sd.pending)sd.pending={};
for(let it of items){
 let d=it.json,url='http://ollama:11434/api/generate',body=JSON.stringify({model:'llama3:8b',prompt:d._prompt,stream:false});
 try{
  let resp=await this.helpers.httpRequest({method:'POST',url,body,headers:{'Content-Type':'application/json'},timeout:120000});
  let reply=String(resp.response||'').trim().substring(0,1500)||'';
  if(!reply||reply==='SKIP'){r.push({json:{_info_only:true,_mid:d._mid}});continue}
  let key='email_'+Date.now();
  sd.pending[key]={email:d._email,sub:d._sub,draft:reply,tid:d._tid};
  let line=d._name+': '+d._sub;
  let tg=line+'\n\n🤖 '+reply+'\n\nReply yes/'+key+' to send';
  let wa=line+'\n\n🤖 '+reply+'\n\nReply with yes/'+key+' to send';
  r.push({json:{_tg:tg,_wa:wa,_reply:reply,_email:d._email,_sub:d._sub,_mid:d._mid,_tid:d._tid,_key:key}})
 }catch(e){r.push({json:{_info_only:true,_mid:d._mid}})}
}
return r

let items=$input.all();
let sd=$getWorkflowStaticData('global');
if(!sd.pending)sd.pending={};
for(let it of items){
 let d=it.json,body=d.body||d,text=(body.text||body.msg||'').trim();
 // Parse: yes/email_12345 or just use latest
 let pending=null;
 let match=text.match(/yes\/(email_\d+)/i);
 if(match&&sd.pending[match[1]]){pending=sd.pending[match[1]];delete sd.pending[match[1]]}
 else{
  let keys=Object.keys(sd.pending);
  if(keys.length>0){pending=sd.pending[keys[0]];delete sd.pending[keys[0]]}
 }
 if(!pending)continue;
 return [{json:{_email:pending.email,_sub:pending.sub,_draft:pending.draft,_tid:pending.tid}}]
}
return items
